import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error('Holdings parse error:', e);
      return [];
    }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data || []);
    } catch (err) {
      console.error(err);
      toast.error('Failed to load vault');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this strategy permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((item) => item.id !== id));
      toast.success('Strategy deleted');
    } catch (err) {
      toast.error('Delete failed');
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id || 'export'}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Download started');
    } catch (err) {
      toast.error('Export failed');
    }
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  if (loading) {
    return <div style={centerStyle}>Loading vault…</div>;
  }

  return (
    <div style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={20} color="var(--accent)" /> Strategy Vault
        </h2>
        <span style={nodeCount}>
          {history.length} {history.length === 1 ? 'entry' : 'entries'}
        </span>
      </div>

      {history.length === 0 ? (
        <div style={emptyStyle}>No saved strategies yet.</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={12} />
                    {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={12} />
                    Risk: {item.risk_score ?? '—'}
                  </span>
                </div>

                <h4 style={titleStyle}>{item.goal || 'Unnamed strategy'}</h4>

                <div style={tickerRow}>
                  {safeParseHoldings(item.holdings).map((ticker, idx) => (
                    <span key={idx} style={tickerTag}>
                      {ticker}
                    </span>
                  ))}
                </div>
              </div>

              <div style={actionRow}>
                <button
                  onClick={() => setSelectedItem(item)}
                  style={iconBtn}
                  title="View details"
                  type="button"
                >
                  <Eye size={18} />
                </button>
                <button
                  onClick={() => handleDownload(item)}
                  style={iconBtn}
                  title="Download PDF"
                  type="button"
                >
                  <Download size={18} />
                </button>
                <button
                  onClick={() => handleDelete(item.id)}
                  style={deleteBtn}
                  title="Delete"
                  type="button"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedItem && (
        <div style={modalOverlay} onClick={() => setSelectedItem(null)}>
          <div style={modalContent} onClick={(e) => e.stopPropagation()}>
            <div style={modalHeader}>
              <h3 style={modalTitle}>Strategy #{selectedItem.id}</h3>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}>
                <X size={22} />
              </button>
            </div>

            <div style={modalBody}>
              <div style={section}>
                <div style={sectionLabel}>Summary</div>
                <div style={sectionContent}>
                  {selectedItem.summary || 'No summary available.'}
                </div>
              </div>

              <div style={section}>
                <div style={sectionLabel}>Rationale</div>
                <div style={sectionContent}>
                  {selectedItem.rationale || 'No rationale provided.'}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ────────────────────────────────────────────────
   Dark-mode optimized styles
───────────────────────────────────────────────── */

const containerStyle = {
  padding: '2rem 1.25rem',
  maxWidth: '1140px',
  margin: '0 auto',
  minHeight: '80vh',
};

const headerRow = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '2.25rem',
  paddingBottom: '1rem',
  borderBottom: '1px solid var(--border-visible)',
};

const headerStyle = {
  color: 'var(--text-strong)',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontSize: '1.28rem',
  fontWeight: 600,
  margin: 0,
};

const nodeCount = {
  fontSize: '0.82rem',
  color: 'var(--text-muted)',
  fontFamily: 'ui-monospace, monospace',
};

const listStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: '1.1rem',
};

const cardStyle = {
  display: 'flex',
  padding: '1.4rem 1.6rem',
  background: 'var(--surface-glass)',
  border: '1px solid var(--border-visible)',
  borderRadius: '14px',
  gap: '1.5rem',
  transition: 'all 0.18s ease',
  ':hover': {
    transform: 'translateY(-3px)',
    boxShadow: '0 16px 40px rgba(0,0,0,0.38)',
    borderColor: 'var(--border-accent)',
  },
};

const tagRow = {
  display: 'flex',
  gap: '1rem',
  marginBottom: '0.8rem',
  flexWrap: 'wrap',
};

const dateTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--text-muted)',
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const riskTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--accent-dimmed)',
  fontWeight: 500,
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const titleStyle = {
